-- ----------------------------
-- Table structure for feedbacks
-- ----------------------------
DROP TABLE IF EXISTS `feedbacks`;
CREATE TABLE `feedbacks` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `category` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `content` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `contact` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `admin_reply` longtext COLLATE utf8mb4_unicode_ci,
  `handled_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `handled_by_id` bigint DEFAULT NULL,
  `user_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `feedbacks_handled_by_id_ba50227c_fk_users_id` (`handled_by_id`),
  KEY `feedbacks_status_2eb89111` (`status`),
  KEY `feedbacks_status_e7bc93_idx` (`status`,`created_at`),
  KEY `feedbacks_user_id_c7b83f_idx` (`user_id`,`created_at`),
  CONSTRAINT `feedbacks_handled_by_id_ba50227c_fk_users_id` FOREIGN KEY (`handled_by_id`) REFERENCES `users` (`id`),
  CONSTRAINT `feedbacks_user_id_be6417c2_fk_users_id` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=52 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

