  `original_filename` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `extracted_text` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `parse_status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `parse_error` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_active` tinyint(1) NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `knowledge_d_role_sc_243467_idx` (`role_scope`,`is_active`),
  KEY `knowledge_d_parse_s_b79af0_idx` (`parse_status`,`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

