-- ----------------------------
-- Table structure for order_logs
-- ----------------------------
DROP TABLE IF EXISTS `order_logs`;
CREATE TABLE `order_logs` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `action` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `remark` longtext COLLATE utf8mb4_unicode_ci,
  `create_time` datetime(6) NOT NULL,
  `operator_id` bigint DEFAULT NULL,
  `work_order_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `order_logs_operator_id_2c114137_fk_users_id` (`operator_id`),
  KEY `order_logs_work_order_id_f1e2cda2_fk_work_orders_id` (`work_order_id`),
  CONSTRAINT `order_logs_operator_id_2c114137_fk_users_id` FOREIGN KEY (`operator_id`) REFERENCES `users` (`id`),
  CONSTRAINT `order_logs_work_order_id_f1e2cda2_fk_work_orders_id` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=462 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

