-- ----------------------------
-- Table structure for qa_logs
-- ----------------------------
DROP TABLE IF EXISTS `qa_logs`;
CREATE TABLE `qa_logs` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `role` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `question` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `answer` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `success` tinyint(1) NOT NULL,
  `error_message` longtext COLLATE utf8mb4_unicode_ci,
  `created_at` datetime(6) NOT NULL,
  `user_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `qa_logs_role_77fda7_idx` (`role`,`created_at`),
  KEY `qa_logs_success_532d99_idx` (`success`,`created_at`),
  KEY `qa_logs_user_id_39e2feb1_fk_users_id` (`user_id`),
  CONSTRAINT `qa_logs_user_id_39e2feb1_fk_users_id` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=41 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ----------------------------
-- Records of qa_logs
-- ----------------------------
BEGIN;
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (29, '学生', '宿舍漏水先做什么？', '如发现持续漏水，建议先关闭水源并尽快提交工单；若有积水需注意防滑，并联系宿管协助。', 1, NULL, '2026-04-16 13:17:14.096451', 6);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (30, '学生', '工单完成后还能再评价吗？', '每个已完成工单只允许评价一次，提交后不能重复修改，请在确认问题处理结果后再提交。', 1, NULL, '2026-04-15 12:17:14.097105', 7);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (31, '学生', '审核一般多久完成？', '管理员会尽快审核，若问题紧急建议在描述中明确风险点，系统会优先安排处理。', 1, NULL, '2026-04-14 11:17:14.097414', 8);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (32, '学生', '反馈记录在哪里看？', '你可以在导航中的“反馈”页面查看反馈记录、状态和管理员回复。', 1, NULL, '2026-04-13 10:17:14.097701', 9);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (33, '维修人员', '接单后第一步该做什么？', '接单后应先确认故障位置与影响范围，必要时联系学生确认现场情况，再准备工具和耗材。', 1, NULL, '2026-04-12 09:17:14.097994', 3);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (34, '维修人员', '完工时要填什么？', '维修完成后需填写维修说明，如有耗材或更换部件建议一并备注，必要时上传维修凭证。', 1, NULL, '2026-04-11 08:17:14.098309', 4);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (35, '维修人员', '知识库没有对应答案怎么办？', '可先根据通用维修规范给出稳妥建议，并提醒用户以管理员发布规则为准。', 1, NULL, '2026-04-10 07:17:14.098644', 5);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (36, '学生', '网络波动怎么处理？', '可先确认是否仅单个设备异常，再检查宿舍路由器、网线或校园网认证状态，必要时提交网络类工单。', 1, NULL, '2026-04-09 06:17:14.098929', 10);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (37, '学生', '空调报修', '请按以下步骤提交空调报修，以便快速响应：\n\n✅ **报修前请确认并补充以下信息**（依据[学校规则]《空调报修提醒》）：  \n- 空调是否通电？（如指示灯是否亮、遥控器是否有反应）  \n- 故障现象：不制冷/不制热？制冷/热效果差？有异响、异味或漏水？  \n- 出现时间（如“昨晚开始不制冷”）、影响程度（如“整晚无法入睡”）  \n- 是否存在安全隐患（如外壳发烫、冒烟、滴水严重等）  \n\n⚠️ 若发现**明显漏水、持续滴水导致地面积水**，请立即：  \n→ 关闭空调电源；  \n→ 如漏水严重，参照[FAQ]《常见漏水问题处理》，**优先关闭宿舍总水源阀**（通常位于卫生间或阳台管道井），并联系宿管协助；  \n→ 再尽快在 DormFix 系统提交报修。\n\n📌 提交后，工单将进入「待审核」状态（见[FAQ]《工单状态含义》），管理员会按紧急程度优先审核派单。\n\n需要我帮你拟一段清晰的报修描述吗？😊', 1, NULL, '2026-04-16 13:30:25.204842', 6);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (38, '学生', '咱们最近有啥报修通知嘛', '目前 DormFix 系统**没有发布新的全校性报修通知**（如系统升级、集中检修等）。但根据知识库中的[学校规则]《高峰期服务说明》，近期可能处于报修高峰期，工单处理时效**可能略有延长**，系统会按紧急程度优先派单，请您耐心等待。\n\n温馨提示：  \n✅ 若您的报修已提交，可随时在「我的工单」中查看实时状态（如待审核、已派单、维修中等）；  \n✅ 如遇**漏水、断电、空调严重异响/漏水、网络大面积中断等紧急情况**，建议同步联系宿管或拨打后勤值班电话（如有），以便加快响应。\n\n需要我帮您快速检查某类常见问题（如空调、网络、漏水）的自查或报修要点吗？', 1, NULL, '2026-04-17 07:57:32.854852', 6);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (39, '学生', '最近有关空调报修的通知', '根据学校最新通知，关于空调报修有以下重要提醒（依据知识库「空调报修提醒」）：\n\n✅ **报修时请务必补充以下信息**，以便快速响应和精准维修：  \n- 空调是否正常通电（如：插头已插、开关已开、断路器未跳闸）；  \n- 具体异常表现：不制冷/不制热？制冷/热效果差？  \n- 是否有异响（如嗡鸣、咔哒声）、异味或漏水现象；  \n- 故障发生的大致时间及是否间歇性出现。\n\n⚠️ 温馨提示：  \n- 若空调漏水严重或伴随明显异味、冒烟等安全隐患，请立即关闭电源，并**优先联系宿管协助**（参考「常见漏水问题处理」）；  \n- 高峰期（如开学初、换季时）维修响应可能略有延迟，系统将按紧急程度优先派单（参考「高峰期服务说明」）。\n\n需要我帮你拟一段清晰的空调报修描述吗？ 😊', 1, NULL, '2026-04-17 07:58:01.770763', 6);
INSERT INTO `qa_logs` (`id`, `role`, `question`, `answer`, `success`, `error_message`, `created_at`, `user_id`) VALUES (40, '维修人员', '我们维修工最近学校有啥通知', '根据知识库内容，学校近期与维修工作相关的重要通知有以下两条：\n\n1. **【高峰期服务说明】**  \n   当前处于报修高峰期，处理时效可能略有延长。系统会按问题的**紧急程度自动排序派单**，请优先处理标有“紧急”“安全风险”（如漏水、断电、消防隐患等）的工单。\n\n2. **【维修员接单规范】**  \n   接单后须**尽快确认现场情况**；若因故无法按时上门、需延期或无法处理，务必在系统中**及时备注原因并反馈管理员**，避免工单滞留。\n\n其他提醒（依据SOP和规则）：  \n- 开始维修前，请务必完成**安全检查**（如断电/断水、工具耗材齐备、故障定位准确）；  \n- 维修完成后，须规范填写**维修说明**，注明更换部件/耗材，并**上传必要凭证图片**。\n\n如需查看具体未读通知，建议登录 DormFix 系统首页「消息中心」或「公告栏」——管理员通常会在那里同步临时调度安排或政策更新。\n\n需要我帮你解读某类工单（如网络/漏水）的处理要点吗？', 1, NULL, '2026-04-17 08:35:36.844392', 3);
COMMIT;

-- ----------------------------
-- Table structure for repair_types
